t.script:
document.addEventListener("DOMContentLoaded", async function () {
    const errorBox = document.getElementById("ndi_error_box");
    const qrImg = document.getElementById("ndi_qr_img");
    const openBtn = document.getElementById("ndi_open_btn");
    const statusText = document.getElementById("ndi_status_text");
    const loader = document.getElementById("ndi_loader_overlay");
    const loaderText = document.getElementById("ndi_loader_text");

    let pollTimer = null;
    let qrGenerated = false;

    function showLoader(message) {
        if (loader) {
            loader.style.display = "flex";
        }
        if (loaderText && message) {
            loaderText.innerText = message;
        }
    }

    function hideLoader() {
        if (loader) {
            loader.style.display = "none";
        }
    }

    async function createProofAndRefreshQr() {
        const response = await fetch("/ndi/login/create-proof", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({})
        });

        const data = await response.json();

        if (!response.ok || !data.ok) {
            throw new Error(data.error || "Failed to create proof");
        }

        qrImg.src = data.qr_src + "?t=" + Date.now();
        openBtn.href = data.deep_link_url;
        return data;
    }

    async function pollStatus() {
        try {
            const response = await fetch("/ndi/login/status", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({})
            });

            const data = await response.json();
            const result = data.result || data || {};

            console.log("NDI STATUS:", result);

            if (result.status === "validated") {
                const successMessage = result.message || "Login successful. Redirecting...";

                statusText.innerText = successMessage;
                showLoader(successMessage);

                if (pollTimer) {
                    clearInterval(pollTimer);
                    pollTimer = null;
                }

                setTimeout(function () {
                    window.location.href = result.redirect_url || "/";
                }, 1200);

                return;
            }

            if (result.status === "pending") {
                if (statusText.innerText === "Scan QR with Bhutan NDI Wallet") {
                    return;
                }
                statusText.innerText = result.message || "Waiting for wallet approval...";
                return;
            }

            if (result.status === "rejected") {
                hideLoader();
                statusText.innerText = "User rejected request";

                if (pollTimer) {
                    clearInterval(pollTimer);
                    pollTimer = null;
                }
                return;
            }

            if (result.status === "error") {
                hideLoader();
                statusText.innerText = result.message || "Verification failed";

                if (pollTimer) {
                    clearInterval(pollTimer);
                    pollTimer = null;
                }
                return;
            }

            if (result.status === "missing") {
                hideLoader();
                statusText.innerText = "Session expired. Please try again.";

                if (pollTimer) {
                    clearInterval(pollTimer);
                    pollTimer = null;
                }
                return;
            }

            statusText.innerText = "Scan QR with Bhutan NDI Wallet";
        } catch (err) {
            console.log("NDI status poll error:", err);
        }
    }

    try {
        errorBox.style.display = "none";
        errorBox.innerText = "";
        hideLoader();

        statusText.innerText = "Generating NDI QR...";

        await createProofAndRefreshQr();

        statusText.innerText = "Scan QR with Bhutan NDI Wallet";

        qrGenerated = true;
        pollTimer = setInterval(pollStatus, 2000);

    } catch (err) {
        errorBox.style.display = "block";
        errorBox.innerText = err.message || "Something went wrong";
        hideLoader();
    }
});
